+    }
+}
+
+export function updatePredicateQuery(world: World, query: QueryInstance, entity: Entity) {
+    const eid = getEntityId(entity);
+    const matches =
+        query.relationFilters && query.relationFilters.length > 0
+            ? checkQueryWithRelations(world, query, entity)
+            : query.check(world, entity);
+
+    if (query.predicateTracking.length === 0) {
+        if (matches) addEntityToQuery(query, entity);
+        else removeEntityFromQuery(world, query, entity);
+        return;
+    }
+
+    let eventMatches = false;
+    for (const tracking of query.predicateTracking) {
+        const previous = tracking.states[eid] === 1;
+        const current = matchesPredicate(world, tracking.predicate, entity);
+        tracking.states[eid] = current ? 1 : 0;
+        if (
+            (tracking.type === 'add' && !previous && current) ||
+            (tracking.type === 'remove' && previous && !current) ||
+            (tracking.type === 'change' && previous !== current)
+        ) {
+            eventMatches = true;
+        }
+    }
+
+    if (matches && eventMatches) addEntityToQuery(query, entity);
+    else if (!matches) removeEntityFromQuery(world, query, entity);
+}
